script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';
const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const reviewers = [
  { id: 'rev-1', label: 'Reviewer One' },
  { id: 'rev-2', label: 'Reviewer Two' },
  { id: 'rev-3', label: 'Reviewer Three' },
];
writeFileSync('/output/result.json', JSON.stringify({ reviewers, question: input.question }));
console.log(`Fanning out to ${reviewers.length} reviewers`);

import { readFileSync, writeFileSync } from 'fs';
const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const spawned = input.steps?.fan_out?.spawned || [];
writeFileSync('/output/result.json', JSON.stringify({ spawnedCount: spawned.length, summary: `Spawned ${spawned.length} child run(s)` }));
console.log(`Spawned ${spawned.length} child run(s)`);
